import React, { useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FAWTable from '../FAWTable/FAWTable';
import FAWTextarea from '../FAWTextarea';

/**
 * VersionsTable Component
 * 
 * Displays version history table with editable description field
 * 
 * @param {Object} props
 * @param {Array} props.initialData - Initial versions data
 * @param {Function} props.onVersionClick - Callback when version link is clicked
 * @param {Function} props.onRowUpdate - Callback when row is updated (Active or Description)
 * @param {boolean} props.loading - Loading state
 */
const VersionsTable = ({
    initialData = [],
    onVersionClick,
    onRowUpdate,
    loading = false
}) => {
    const [data, setData] = useState(initialData);

    // Update data when initialData changes
    useEffect(() => {
        setData(initialData);
    }, [initialData]);

    // Handle row update
    const handleRowUpdate = (newRow, oldRow) => {
        // Update local data
        const updatedData = data.map(row => {
            if (row.Id === newRow.Id) {
                return newRow;
            }
            // If Active changed to true, set all other rows to false
            if (newRow.IsActive && !oldRow.IsActive && row.Id !== newRow.Id) {
                return { ...row, IsActive: false };
            }
            return row;
        });
        
        setData(updatedData);

        // Call parent callback
        if (onRowUpdate) {
            onRowUpdate(newRow, oldRow);
        }

        return newRow;
    };

    const columns = [
        {
            headerName: "Version",
            field: "Version",
            type: "link",
            flex: 1,
            minWidth: 100,
            onClick: (params, e) => {
                if (e && typeof e.preventDefault === "function") {
                    e.preventDefault();
                }
                const rowData = params.row || params.data || params;
                const versionId = rowData.Id;
                
                if (onVersionClick) {
                    onVersionClick(versionId);
                }
            }
        },
        {
            headerName: "Active",
            field: "IsActive",
            type: "radio",
            editable: true,
            flex: 1,
            minWidth: 100,
            disabled: (row) => row.disabled || false // Use disabled property from row data
        },
        {
            headerName: "Version Description",
            field: "Description",
            flex: 3,
            minWidth: 300,
            editable: false,
            renderCell: (params) => {
                const [localValue, setLocalValue] = useState(params.value || '');
                const [isFocused, setIsFocused] = useState(false);

                useEffect(() => {
                    setLocalValue(params.value || '');
                }, [params.value]);

                const handleChange = (event) => {
                    const newValue = event.target.value;
                    setLocalValue(newValue);
                };

                const handleBlur = () => {
                    setIsFocused(false);
                    // Only trigger update if value changed
                    if (localValue !== params.value) {
                        const updatedRow = { ...params.row, Description: localValue };
                        handleRowUpdate(updatedRow, params.row);
                    }
                };

                const handleFocus = () => {
                    setIsFocused(true);
                };

                return (
                    <Box 
                        className="version-description-cell-box"
                        sx={{ 
                            width: '100%',      
                            maxWidth: '100%',
                            display: 'flex',
                            alignItems: 'flex-start',
                            padding: 0,
                            margin: 0,
                            boxSizing: 'border-box'
                        }}
                    >
                        <FAWTextarea
                            className="version-description-input"
                            value={localValue}
                            onChange={handleChange}
                            onBlur={handleBlur}
                            onFocus={handleFocus}
                            rows={1}
                            fullWidth
                            multiline={false}
                            sx={{
                                fontSize: '14px',
                                width: '100%',
                                maxWidth: '100%',
                                minWidth: '100%',
                                flex: 1,
                                '& .MuiInputBase-root': {
                                    minHeight: 'auto',
                                    height: '100%',
                                    width: '100%',
                                    maxWidth: '100%',
                                    backgroundColor: 'transparent',
                                    padding: '8px 12px',
                                    border: 'none',
                                    boxSizing: 'border-box',
                                    display: 'flex',
                                    alignItems: 'center',
                                    '& fieldset': { border: 'none' },
                                    '&:hover fieldset': { border: 'none' },
                                    '&.Mui-focused fieldset': { border: 'none' },
                                },
                                '& .MuiOutlinedInput-input': {
                                    padding: '4px 6px',
                                    margin: 0,
                                    width: '100%',
                                    maxWidth: '100%',
                                    height: 'auto',
                                    whiteSpace: 'nowrap',
                                    overflow: 'auto',
                                    border: isFocused ? '1px solid #282e37' : '1px solid transparent',
                                    borderRadius: '4px',
                                    transition: 'border-color 0.2s ease',
                                    boxSizing: 'border-box',
                                },
                                '& input': {
                                    width: '100%',
                                    maxWidth: '100%',
                                    minWidth: '100%',
                                    boxSizing: 'border-box',
                                    overflow: 'auto',
                                    whiteSpace: 'nowrap',
                                    padding: '4px 6px',
                                    margin: 0,
                                    height: 'auto',
                                    border: isFocused ? '1px solid #282e37' : '1px solid transparent',
                                    borderRadius: '4px',
                                    transition: 'border-color 0.2s ease',
                                },
                            }}
                            onKeyDown={(e) => {
                                e.stopPropagation();
                            }}
                        />
                    </Box>
                );
            }
        }
    ];

    // Always render - visibility controlled by container display style (like ag-grid)
    return (
        <FAWTable
            columns={columns}
            rows={data}
            loading={loading}
            showToolbar={false}
            showSearch={false}
            showFilter={false}
            showColumns={false}
            showExport={false}
            hideReset={true}
            showPagination={true}
            autoHeight={true}
            rowHeight={60}
            emptyStateTitle="No versions found."
            emptyStateMessage="Create your first version to track changes."
            emptyStateNoResultsTitle="No matching versions"
            emptyStateNoResultsMessage="Try adjusting your search terms."
            getRowId={(row) => row.Id}
            processRowUpdate={handleRowUpdate}
            getRowHeight={() => 'auto'}
            className="versions-table"
        />
    );
};

export default VersionsTable;

